preferences.postscript:
if (Translator.BetterBibTeX) {
  Zotero.debug('Postscript running for item: ' + zotero.title);
  if (zotero.creators && zotero.creators.length) {
    for (let creator of zotero.creators) {
      const lastNorm = creator.lastName.replace(/\./g,'').trim().toLowerCase();
      const firstNorm = creator.firstName.replace(/\./g,'').trim().toLowerCase();
      // Standardize Stokes
      if (lastNorm === 'stokes') creator.firstName = 'Donald E.';
      // Standardize Tideman
      if (lastNorm === 'tideman') creator.firstName = 'Nicolaus';
      // Standardize Young
      if (lastNorm === 'young') creator.firstName = 'H. Peyton';
    }
    // Apply the modified creators to the BibTeX export
    tex.addCreators();  // NO arguments!
    Zotero.debug('Updated creators for export: ' + zotero.creators.map(c => c.firstName + ' ' + c.lastName).join(', '));
  } else {
    Zotero.debug('No creators found for this item.');
  }
}
